// TanStack Query hooks for categories
// Files: src/lib/queryClient.ts, src/hooks/useCategories.ts, src/hooks/useCategoryMutations.ts

// Import from '@/lib'
export const queryClient: QueryClient;
export const queryKeys: {
  categories: ['categories'];
  category: (id: string) => ['categories', id];
  // ...other query keys
};

// Import from '@/hooks'

// useCategories
export interface UseCategoriesOptions {
  enabled?: boolean;
  staleTime?: number;
}
export function useCategories(options?: UseCategoriesOptions): UseQueryResult<Category[]>;
export class CategoriesFetchError extends Error { code?: string; }

// useCategoryMutations
export function useCreateCategory(): UseMutationResult<Category, CategoryMutationError, CreateCategoryInput>;
export function useUpdateCategory(): UseMutationResult<Category, CategoryMutationError, { id: string; data: UpdateCategoryInput }>;
export function useDeleteCategory(): UseMutationResult<void, CategoryMutationError, string>;
export class CategoryMutationError extends Error { code?: string; operation?: 'create' | 'update' | 'delete'; }

// Behavior notes:
// - QueryClient: staleTime 5min, gcTime 30min, refetchOnWindowFocus: false
// - useCategories fetches from supabase.from('categories').select('*').order('name')
// - Mutations validate with CreateCategorySchema/UpdateCategorySchema (NOT full CategorySchema)
// - All mutations implement optimistic updates via onMutate/onError/onSettled
// - Cache invalidation on mutation settled
